class Solution:
    def alternatingSum(self, nums):
        total = 0
        for i in range(len(nums)):
            if i % 2 == 0:
                total = total + nums[i]
            else:
                total = total - nums[i]
        return total

solutions.python:
class Solution:
    def alternatingSum(self, nums):
        sign = 1
        total = 0
        for x in nums:
            total += sign * x
            sign = -sign
        return total

